const fs = require('fs');

// MIPS Register names
const REG_NAMES = [
  'zero', 'at', 'v0', 'v1', 'a0', 'a1', 'a2', 'a3',
  't0', 't1', 't2', 't3', 't4', 't5', 't6', 't7',
  's0', 's1', 's2', 's3', 's4', 's5', 's6', 's7',
  't8', 't9', 'k0', 'k1', 'gp', 'sp', 'fp', 'ra'
];

// System call numbers
const SYSCALL_NUMBERS = {
  EXIT: 60,
  WRITE: 1,
  OPEN: 2,
  CLOSE: 3,
  READ: 0,
  MMAP: 9,
  IOCTL: 16,
  SLEEP_MS: 35,  // Custom for usleep
  GET_TIME: 78   // gettimeofday
};

// Main VM class
class MIPSVM {
  constructor() {
    // Initialize registers
    this.registers = new Uint32Array(32);
    this.pc = 0;
    this.frameCount = 0;

    // Initialize memory (4MB)
    this.memory = new Uint8Array(4 * 1024 * 1024);

    // File descriptors
    this.fdTable = {};
    this.nextFd = 3; // 0, 1, 2 are reserved for stdin, stdout, stderr
  }

  // Load ELF file
  loadELF(filename) {
    const buffer = fs.readFileSync(filename);

    // Parse ELF header
    const elfHeader = {
      magic: buffer.slice(0, 4),
      class: buffer[4],
      data: buffer[5],
      version: buffer[6],
      osabi: buffer[7],
      abiversion: buffer[8],
      type: buffer.readUInt16LE(16),
      machine: buffer.readUInt16LE(18),
      entry: buffer.readUInt32LE(24)
    };

    console.log(`ELF Entry Point: 0x${elfHeader.entry.toString(16)}`);

    // For simplicity, we'll just load at fixed address
    // In a real implementation, we'd parse program headers
    buffer.copy(this.memory, 0x400000, 0);
    this.pc = elfHeader.entry;

    return elfHeader.entry;
  }

  // Read a 32-bit word from memory
  readWord(address) {
    // Ensure address is word-aligned
    const addr = address & 0xFFFFFFFC;
    if (addr >= this.memory.length - 3) return 0;

    return (
      (this.memory[addr] << 0) |
      (this.memory[addr + 1] << 8) |
      (this.memory[addr + 2] << 16) |
      (this.memory[addr + 3] << 24)
    ) >>> 0; // Unsigned right shift to ensure unsigned result
  }

  // Write a 32-bit word to memory
  writeWord(address, value) {
    // Ensure address is word-aligned
    const addr = address & 0xFFFFFFFC;
    if (addr >= this.memory.length - 3) return;

    this.memory[addr] = (value >> 0) & 0xFF;
    this.memory[addr + 1] = (value >> 8) & 0xFF;
    this.memory[addr + 2] = (value >> 16) & 0xFF;
    this.memory[addr + 3] = (value >> 24) & 0xFF;
  }

  // Execute a single instruction
  executeInstruction(instruction) {
    // Extract opcode (top 6 bits)
    const opcode = (instruction >>> 26) & 0x3F;

    switch (opcode) {
      case 0x00: // R-type instructions
        this.executeRType(instruction);
        break;
      case 0x02: // j
        this.pc = (this.pc & 0xF0000000) | ((instruction & 0x03FFFFFF) << 2);
        return true; // Jump taken
      case 0x03: // jal
        this.registers[31] = this.pc + 4; // Save return address
        this.pc = (this.pc & 0xF0000000) | ((instruction & 0x03FFFFFF) << 2);
        return true; // Jump taken
      case 0x04: // beq
        const rs = (instruction >>> 21) & 0x1F;
        const rt = (instruction >>> 16) & 0x1F;
        const offset = ((instruction & 0xFFFF) << 16) >> 16; // Sign extend
        if (this.registers[rs] === this.registers[rt]) {
          this.pc += offset << 2;
          return true; // Branch taken
        }
        break;
      case 0x05: // bne
        const rs1 = (instruction >>> 21) & 0x1F;
        const rt1 = (instruction >>> 16) & 0x1F;
        const offset1 = ((instruction & 0xFFFF) << 16) >> 16; // Sign extend
        if (this.registers[rs1] !== this.registers[rt1]) {
          this.pc += offset1 << 2;
          return true; // Branch taken
        }
        break;
      case 0x09: // addiu
        const rt2 = (instruction >>> 16) & 0x1F;
        const rs2 = (instruction >>> 21) & 0x1F;
        const immediate = ((instruction & 0xFFFF) << 16) >> 16; // Sign extend
        this.registers[rt2] = (this.registers[rs2] + immediate) >>> 0; // Unsigned
        break;
      case 0x0C: // andi
        const rt3 = (instruction >>> 16) & 0x1F;
        const rs3 = (instruction >>> 21) & 0x1F;
        const immediate1 = instruction & 0xFFFF;
        this.registers[rt3] = this.registers[rs3] & immediate1;
        break;
      case 0x0F: // lui
        const rt4 = (instruction >>> 16) & 0x1F;
        const immediate2 = (instruction & 0xFFFF) << 16;
        this.registers[rt4] = immediate2;
        break;
      case 0x1A: // div
        const rs5 = (instruction >>> 21) & 0x1F;
        const rt5 = (instruction >>> 16) & 0x1F;
        if (this.registers[rt5] !== 0) {
          this.hi = (this.registers[rs5] % this.registers[rt5]) >>> 0;
          this.lo = (this.registers[rs5] / this.registers[rt5]) >>> 0;
        }
        break;
      case 0x1B: // divu
        const rs6 = (instruction >>> 21) & 0x1F;
        const rt6 = (instruction >>> 16) & 0x1F;
        if (this.registers[rt6] !== 0) {
          this.hi = (this.registers[rs6] % this.registers[rt6]) >>> 0;
          this.lo = (this.registers[rs6] / this.registers[rt6]) >>> 0;
        }
        break;
      case 0x23: // lw
        const rt7 = (instruction >>> 16) & 0x1F;
        const rs7 = (instruction >>> 21) & 0x1F;
        const offset2 = ((instruction & 0xFFFF) << 16) >> 16; // Sign extend
        const address = this.registers[rs7] + offset2;
        this.registers[rt7] = this.readWord(address);
        break;
      case 0x28: // sb
        const rt8 = (instruction >>> 16) & 0x1F;
        const rs8 = (instruction >>> 21) & 0x1F;
        const offset3 = ((instruction & 0xFFFF) << 16) >> 16; // Sign extend
        const address1 = this.registers[rs8] + offset3;
        if (address1 < this.memory.length) {
          this.memory[address1] = this.registers[rt8] & 0xFF;
        }
        break;
      case 0x2B: // sw
        const rt9 = (instruction >>> 16) & 0x1F;
        const rs9 = (instruction >>> 21) & 0x1F;
        const offset4 = ((instruction & 0xFFFF) << 16) >> 16; // Sign extend
        const address2 = this.registers[rs9] + offset4;
        this.writeWord(address2, this.registers[rt9]);
        break;
      case 0x34: // mul
        const rd = (instruction >>> 11) & 0x1F;
        const rs10 = (instruction >>> 21) & 0x1F;
        const rt10 = (instruction >>> 16) & 0x1F;
        this.registers[rd] = Math.imul(this.registers[rs10], this.registers[rt10]) >>> 0;
        break;
      default:
        console.log(`Unhandled opcode: 0x${opcode.toString(16)} at PC 0x${this.pc.toString(16)}`);
        break;
    }

    return false; // No jump/branch taken
  }

  // Execute R-type instruction
  executeRType(instruction) {
    const rs = (instruction >>> 21) & 0x1F;
    const rt = (instruction >>> 16) & 0x1F;
    const rd = (instruction >>> 11) & 0x1F;
    const shamt = (instruction >>> 6) & 0x1F;
    const funct = instruction & 0x3F;

    switch (funct) {
      case 0x00: // sll
        this.registers[rd] = (this.registers[rt] << shamt) >>> 0;
        break;
      case 0x02: // srl
        this.registers[rd] = this.registers[rt] >>> shamt;
        break;
      case 0x03: // sra
        this.registers[rd] = (this.registers[rt] << 0) >> shamt; // Arithmetic right shift
        break;
      case 0x08: // jr
