        return true; // Jump taken
      case 0x09: // jalr
        this.registers[rd] = this.pc + 4;
        this.pc = this.registers[rs];
        return true; // Jump taken
      case 0x10: // mfhi
        this.registers[rd] = this.hi || 0;
        break;
      case 0x12: // mflo
        this.registers[rd] = this.lo || 0;
        break;
      case 0x18: // mult
        const result = Math.imul(this.registers[rs], this.registers[rt]);
        this.hi = (result >>> 32) >>> 0;
        this.lo = (result & 0xFFFFFFFF) >>> 0;
        break;
      case 0x19: // multu
        const result1 = Math.imul(this.registers[rs], this.registers[rt]);
        this.hi = (result1 >>> 32) >>> 0;
        this.lo = (result1 & 0xFFFFFFFF) >>> 0;
        break;
      case 0x20: // add
        this.registers[rd] = (this.registers[rs] + this.registers[rt]) >>> 0;
        break;
      case 0x21: // addu
        this.registers[rd] = (this.registers[rs] + this.registers[rt]) >>> 0;
        break;
      case 0x22: // sub
        this.registers[rd] = (this.registers[rs] - this.registers[rt]) >>> 0;
        break;
      case 0x23: // subu
        this.registers[rd] = (this.registers[rs] - this.registers[rt]) >>> 0;
        break;
      case 0x24: // and
        this.registers[rd] = this.registers[rs] & this.registers[rt];
        break;
      case 0x25: // or
        this.registers[rd] = this.registers[rs] | this.registers[rt];
        break;
      case 0x26: // xor
        this.registers[rd] = this.registers[rs] ^ this.registers[rt];
        break;
      case 0x27: // nor
        this.registers[rd] = ~(this.registers[rs] | this.registers[rt]) >>> 0;
        break;
      case 0x2A: // slt
        this.registers[rd] = (this.registers[rs] < this.registers[rt]) ? 1 : 0;
        break;
      case 0x2B: // sltu
        this.registers[rd] = (this.registers[rs] < this.registers[rt]) ? 1 : 0;
        break;
