  handleSyscall() {
    const syscallNum = this.registers[2]; // v0 register holds syscall number

    switch (syscallNum) {
      case SYSCALL_NUMBERS.EXIT:
        console.log(`Program exited with code ${this.registers[4]}`);
        process.exit(this.registers[4]);
        break;

      case SYSCALL_NUMBERS.WRITE:
        return this.handleWrite();

      case SYSCALL_NUMBERS.OPEN:
        return this.handleOpen();

      case SYSCALL_NUMBERS.CLOSE:
        return this.handleClose();

      case SYSCALL_NUMBERS.READ:
        return this.handleRead();

      case SYSCALL_NUMBERS.MMAP:
        return this.handleMmap();

