      const fd = this.nextFd++;
      this.fdTable[fd] = {
        path: pathname,
        position: 0
      };
      this.registers[2] = fd; // Return file descriptor
    } catch (e) {
      this.registers[2] = -1; // Error
    }
  }

  handleClose() {
    const fd = this.registers[4]; // a0
    if (this.fdTable[fd]) {
      delete this.fdTable[fd];
      this.registers[2] = 0; // Success
    } else {
      this.registers[2] = -1; // Error
    }
  }

  handleRead() {
