  handleWrite() {
    const fd = this.registers[4];    // a0
    const bufAddr = this.registers[5]; // a1
    const count = this.registers[6];  // a2

    console.log(`WRITE syscall: fd=${fd}, bufAddr=0x${bufAddr.toString(16)}, count=${count}`);

