    // Let's check if this looks like frame data
    if (count >= 640 * 400 * 3) {  // At least 640x400 RGB/RGBA frames
      console.log(`Detected potential frame write of ${count} bytes`);
      this.saveFrame(bufAddr, count);
    }

    // For stdout/stderr, just print to console
    if (fd === 1 || fd === 2) {
      let str = '';
      for (let i = 0; i < count && (bufAddr + i) < this.memory.length; i++) {
        const byte = this.memory[bufAddr + i];
        if (byte === 0) break;
        str += String.fromCharCode(byte);
      }
      if (fd === 1) process.stdout.write(str);
      else process.stderr.write(str);
      this.registers[2] = count; // Return number of bytes written
    } else {
      // For other file descriptors, we'll just pretend we wrote successfully
      this.registers[2] = count;
    }
  }

  // Save frame data to a file
  saveFrame(bufAddr, count) {
    const frameData = Buffer.alloc(count);
    for (let i = 0; i < count && (bufAddr + i) < this.memory.length; i++) {
      frameData[i] = this.memory[bufAddr + i];
    }

    const filename = `frame_${this.frameCount.toString().padStart(4, '0')}.bin`;
